"use strict";function parseFilterParameters(){const e=document.querySelector("form");if(!e)return console.warn("No form found on the page. Returning an empty URLSearchParams object."),new URLSearchParams;const t=new FormData(e);return new URLSearchParams(t)}function lockFilter(){document.querySelectorAll(".submit-filter").forEach(t=>{t.value="Loading...",t.textContent="Loading...",t.disabled=!0})}function lockCustomElements(){}function unlockFilter(){document.querySelectorAll(".submit-filter").forEach(t=>{t.value="Filter",t.textContent="Filter",t.disabled=!1})}function unlockCustomElements(){}function clickedFilterButton(){lockFilter()}
